class Solution:
    def lastStoneWeightII(self, stones):
        """
        :type stones: List[int]
        :rtype: int
        """
        total = sum(stones)
        target = total // 2

        # DP to find max sum <= target
        dp = [False] * (target + 1)
        dp[0] = True

        for stone in stones:
            for s in range(target, stone - 1, -1):
                if dp[s - stone]:
                    dp[s] = True

        # Find largest sum achievable
        for s in range(target, -1, -1):
            if dp[s]:
                return total - 2 * s

        return 0
